document.addEventListener("DOMContentLoaded",()=>{let t=document.getElementById("status"),e=document.getElementById("current-url");!t||!e||chrome.tabs.query({active:!0,currentWindow:!0},a=>{let n=a[0];n?.url?(e.textContent=n.url,t.textContent="Ready",t.className="status ready"):(e.textContent="Unable to read tab URL",t.textContent="Unavailable",t.className="status unavailable")})});
